### 8. Getting Session from Headers on the Server Side (`auth.api.getSession`)

On the server, you use `auth.api.getSession()` to extract the session from incoming request headers. This works with both cookie-based and bearer token authentication:

```typescript
import { auth } from "./auth"; // your betterAuth instance

// With a standard Request object (works with Bun.serve, Hono, etc.)
async function handleProtectedRoute(request: Request) {
  const session = await auth.api.getSession({
    headers: request.headers,
  });

  if (!session) {
    return new Response("Unauthorized", { status: 401 });
  }

  // session.user and session.session are available
  return new Response(`Hello ${session.user.name}`);
}
```

**Integration with Bun.serve:**

```typescript
import { auth } from "./auth";

Bun.serve({
  port: 3000,
  async fetch(request) {
    const url = new URL(request.url);

    // Let better-auth handle its own routes
    if (url.pathname.startsWith("/api/auth")) {
      return auth.handler(request);
    }

    // Protected route example
    if (url.pathname.startsWith("/api/protected")) {
      const session = await auth.api.getSession({
        headers: request.headers,
      });

      if (!session) {
        return new Response(JSON.stringify({ error: "Unauthorized" }), {
          status: 401,
          headers: { "Content-Type": "application/json" },
        });
      }

      return new Response(JSON.stringify({
        message: `Hello ${session.user.name}`,
        userId: session.user.id,
      }), {
        headers: { "Content-Type": "application/json" },
      });
    }

    return new Response("Not Found", { status: 404 });
  },
});
```

**With oRPC middleware (relevant to your project):**

```typescript
import { auth } from "./auth";
import { os } from "@orpc/server";

// Create a middleware that extracts the session
const authMiddleware = os.middleware(async ({ context, next }) => {
  const session = await auth.api.getSession({
    headers: context.request.headers,
  });

  if (!session) {
    throw new Error("Unauthorized");
  }

  return next({
    context: {
      ...context,
      session,
      user: session.user,
    },
  });
});
```

