**Concrete example -- the pattern already used in your codebase** (`/Users/marc/conductor/workspaces/gazed/santiago/apps/api/src/index.ts`), extended with a real context:

```typescript
import { RPCHandler } from "@orpc/server/fetch";
import { CORSPlugin } from "@orpc/server/plugins";
import { router } from "./router.js";

const handler = new RPCHandler(router, {
  plugins: [new CORSPlugin()],
});

Bun.serve({
  port: 4010,
  async fetch(request) {
    // When router uses $context<AppContext>(), you MUST provide a matching context
    const { matched, response } = await handler.handle(request, {
      prefix: "/rpc",
      context: {
        request,  // satisfies AppContext.request
      },
    });

    if (matched) {
      return response;
    }
    return new Response("Not found", { status: 404 });
  },
});
```

If you declared `$context<AppContext>()` where `AppContext = { request: Request }`, then TypeScript will enforce that `context: { request: Request }` is provided. If context is `Record<never, never>` (the default), the context property is optional and `{}` suffices.

---

### 6. Throwing ORPCError with Specific Codes

`ORPCError` is re-exported from `@orpc/client` through `@orpc/server`. From `/Users/marc/conductor/workspaces/gazed/santiago/node_modules/.bun/@orpc+client@1.13.5/node_modules/@orpc/client/dist/index.d.ts`, lines 102-131:

```typescript
type ORPCErrorOptions<TData> = ErrorOptions & {
  defined?: boolean;
  status?: number;
  message?: string;
} & (undefined extends TData
  ? { data?: TData }
  : { data: TData });

class ORPCError<TCode extends ORPCErrorCode, TData> extends Error {
  readonly defined: boolean;
  readonly code: TCode;
  readonly status: number;
  readonly data: TData;
  constructor(code: TCode, ...rest: MaybeOptionalOptions<ORPCErrorOptions<TData>>);
  toJSON(): ORPCErrorJSON<TCode, TData>;
}
```

The **built-in error codes** with their default statuses (lines 20-97):

| Code | Status | Default Message |
|------|--------|----------------|
| `BAD_REQUEST` | 400 | Bad Request |
| `UNAUTHORIZED` | 401 | Unauthorized |
| `FORBIDDEN` | 403 | Forbidden |
| `NOT_FOUND` | 404 | Not Found |
| `METHOD_NOT_SUPPORTED` | 405 | Method Not Supported |
| `TIMEOUT` | 408 | Request Timeout |
| `CONFLICT` | 409 | Conflict |
| `UNPROCESSABLE_CONTENT` | 422 | Unprocessable Content |
| `TOO_MANY_REQUESTS` | 429 | Too Many Requests |
| `INTERNAL_SERVER_ERROR` | 500 | Internal Server Error |
| ... | ... | ... |

**Concrete examples:**

```typescript
import { ORPCError } from "@orpc/server";

// Basic - uses default message "Unauthorized" and status 401
throw new ORPCError("UNAUTHORIZED");

// With custom message
throw new ORPCError("UNAUTHORIZED", { message: "Token expired" });

// With structured data
throw new ORPCError("FORBIDDEN", {
  message: "Insufficient permissions",
  data: { requiredRole: "admin" },
});

// Custom status override (rarely needed since codes have sensible defaults)
throw new ORPCError("BAD_REQUEST", {
  status: 400,
  message: "Validation failed",
  data: { field: "email", issue: "invalid format" },
});
```

Additionally, inside middleware, the `errors` parameter gives access to **typed error constructors** from the contract's error map (from `server.qKsRrdxW.d.ts`, lines 10-15):

```typescript
// In middleware options, `errors` is an ORPCErrorConstructorMap
// If your contract defines typed errors, you can use:
const authMiddleware = os.middleware(async ({ context, next, errors }) => {
  // errors.UNAUTHORIZED() -- creates a typed ORPCError if UNAUTHORIZED is in the error map
  // But for general middleware, direct `new ORPCError(...)` or `throw new ORPCError(...)` works
});
```

---

### 7. Overall Pattern for Protected vs Public Routes with Middleware

Putting it all together. Here is the complete pattern:

```typescript
// ---- contract (packages/api-routes/src/index.ts) ----
import { oc } from "@orpc/contract";
import { z } from "zod";

export const contract = {
  health: oc.output(z.object({
    status: z.literal("ok"),
    timestamp: z.number(),
  })),
  getProfile: oc.output(z.object({
    id: z.string(),
    email: z.string(),
  })),
  listUsers: oc
    .input(z.object({ limit: z.number().optional() }))
    .output(z.array(z.object({ id: z.string(), email: z.string() }))),
};

// ---- server (apps/api/src/router.ts) ----
import { implement, ORPCError } from "@orpc/server";
import { contract } from "@repo/api-routes";

// 1. Define your context types
interface AppContext {
  request: Request;
}

interface AuthContext {
  user: { id: string; email: string };
}

// 2. Create the implementer with typed context
const os = implement(contract).$context<AppContext>();

// 3. Create auth middleware
const authMiddleware = os.middleware(async ({ context, next }) => {
  const token = context.request.headers.get("authorization")?.replace("Bearer ", "");

  if (!token) {
    throw new ORPCError("UNAUTHORIZED", { message: "Missing authorization header" });
  }

  const user = await verifyToken(token);
  if (!user) {
    throw new ORPCError("UNAUTHORIZED", { message: "Invalid or expired token" });
  }

  // Merge { user } into context for downstream
  return next({ context: { user } });
});

// 4. PUBLIC route -- no middleware, handler receives AppContext
const health = os.health.handler(({ context }) => {
  // context.request is available, but no context.user
  return { status: "ok" as const, timestamp: Date.now() };
});

// 5. PROTECTED route -- apply authMiddleware, handler receives AppContext & AuthContext
const getProfile = os.getProfile
  .use(authMiddleware)
  .handler(({ context }) => {
    // context.user is typed as { id: string; email: string }
    // context.request is also still available
    return { id: context.user.id, email: context.user.email };
  });

// 6. Another PROTECTED route
const listUsers = os.listUsers
  .use(authMiddleware)
  .handler(async ({ context, input }) => {
    // context.user is available
    // input is typed as { limit?: number }
    return await db.users.findMany({ take: input.limit ?? 10 });
  });

// 7. Compose the router
export const router = os.router({
  health,
  getProfile,
  listUsers,
});

// ---- server entry (apps/api/src/index.ts) ----
import { RPCHandler } from "@orpc/server/fetch";
import { CORSPlugin } from "@orpc/server/plugins";
import { router } from "./router.js";

const handler = new RPCHandler(router, {
  plugins: [new CORSPlugin()],
});

Bun.serve({
  port: 4010,
  async fetch(request) {
    // 8. Pass initial context matching AppContext
    const { matched, response } = await handler.handle(request, {
      prefix: "/rpc",
      context: { request },
    });

    if (matched) {
      return response;
    }
    return new Response("Not found", { status: 404 });
  },
});
```

**Alternative: Apply middleware to a group of routes** using `.use()` at the router level:

```typescript
// All routes under this will require auth
const protectedOs = os.use(authMiddleware);

// Now every procedure implemented from protectedOs has context.user
const getProfile = protectedOs.getProfile.handler(({ context }) => {
  return { id: context.user.id, email: context.user.email };
});

const listUsers = protectedOs.listUsers.handler(async ({ context, input }) => {
  return await db.users.findMany({ take: input.limit ?? 10 });
});

// Mix public and protected in the final router
export const router = os.router({
  health,       // public (implemented directly from os)
  getProfile,   // protected (implemented from protectedOs)
  listUsers,    // protected
});
```

